+					tool_call_id: "call_1",
+					content: [
+						{
+							kind: "tool_result",
+							tool_result: {
+								tool_call_id: "call_1",
+								content: "file contents",
+								is_error: false,
+							},
+						},
+					],
+				},
+			}),
+			pricingSnapshot,
